// src/pages/FarmDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';
import speciesData from '../data/speciesData';

function FarmDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const [farm, setFarm] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // FIX: Hợp nhất các state bị trùng lặp thành một state duy nhất
  const [activityFormData, setActivityFormData] = useState({
    speciesName: '',        // Dùng cho dropdown cũ
    newSpeciesName: '',   // Dùng cho mục đăng ký mới
    newScientificName: '',// Dùng cho mục đăng ký mới
    date: '',
    increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
    decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
    reasonForChange: '',
  });

  // State để điều khiển giao diện của chức năng mới
  const [selectedNewSpecies, setSelectedNewSpecies] = useState('');
  const [isManualEntry, setIsManualEntry] = useState(false);

  const fetchFarmDetails = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const resFarm = await axios.get(`http://localhost:10000/api/farms/${farmId}`, { headers: { Authorization: `Bearer ${token}` } });
      setFarm(resFarm.data);

      if (resFarm.data.loaiDongVatRung && resFarm.data.loaiDongVatRung[0]) {
        setActivityFormData(prev => ({ ...prev, speciesName: resFarm.data.loaiDongVatRung[0].tenLamSan }));
      }
      
      const resActivities = await axios.get(`http://localhost:10000/api/farm-activities/${farmId}`, { headers: { Authorization: `Bearer ${token}` } });
      setActivities(resActivities.data);
    } catch (err) {
      setError('Could not load farm details.');
    } finally {
      setLoading(false);
    }
  }, [farmId, token]);

  useEffect(() => {
    if (farmId && token) fetchFarmDetails();
  }, [farmId, token, fetchFarmDetails]);

  const handleActivityFormChange = (e) => {
    const { name, value } = e.target;
    let newFormData = { ...activityFormData };
    if (['speciesName', 'date', 'reasonForChange', 'newSpeciesName', 'newScientificName'].includes(name)) {
      newFormData[name] = value;
    } else {
      const [mainField, subField, prop] = name.split('.');
      newFormData = {
        ...newFormData,
        [mainField]: { ...newFormData[mainField], [subField]: { ...newFormData[mainField][subField], [prop]: parseInt(value, 10) || 0 } },
      };
    }
    setActivityFormData(newFormData);
  };

  const handleNewSpeciesChange = (e) => {
    const value = e.target.value;
    setSelectedNewSpecies(value);
    setActivityFormData(prev => ({ ...prev, speciesName: '' }));

    if (value === 'Nhập thủ công') {
      setIsManualEntry(true);
      setActivityFormData(prev => ({ ...prev, newSpeciesName: '', newScientificName: '' }));
    } else if (value === '') {
      setIsManualEntry(false);
      setActivityFormData(prev => ({ ...prev, newSpeciesName: '', newScientificName: '' }));
    } else {
      setIsManualEntry(false);
      const matched = speciesData.find(s => s.tenLamSan === value);
      if (matched) {
        setActivityFormData(prev => ({
          ...prev,
          newSpeciesName: matched.tenLamSan,
          newScientificName: matched.tenKhoaHoc,
        }));
      }
    }
  };

  const handleAddActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');
    try {
      // FIX: Sửa lại logic bị lỗi cú pháp
      const finalSpeciesName = activityFormData.newSpeciesName || activityFormData.speciesName;
      const finalScientificName = activityFormData.newScientificName;

      const dataToSend = { 
        ...activityFormData, 
        speciesName: finalSpeciesName, 
        scientificName: finalScientificName, 
        farm: farmId 
      };
      
      delete dataToSend.newSpeciesName;
      delete dataToSend.newScientificName;

      const res = await axios.post(`http://localhost:10000/api/farm-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setMessage('Tracking record added successfully!');
      setActivities(prevActivities => [...prevActivities, res.data]);
      
      // Reset form
      setActivityFormData(prev => ({
        ...prev, date: '', reasonForChange: '', newSpeciesName: '', newScientificName: '',
        increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
      }));
      setSelectedNewSpecies('');
      setIsManualEntry(false);
    } catch (err) {
      setError(err.response?.data?.message || 'Error adding tracking record.');
    }
  };
  
  const handleDeleteActivity = async (activityId) => { /* ... giữ nguyên ... */ };

  if (loading) return <div className="form-container"><p>Loading data...</p></div>;
  if (error) return <div className="form-container"><p style={{ color: 'red' }}>Error: {error}</p></div>;
  if (!farm) return <div className="form-container"><p>No farm information found.</p></div>;

  return (
    <div className="form-container">
      <style>{/* ... style giữ nguyên ... */}</style>
      <h2>👁️ Logbook: {farm.tenCoSo}</h2>
      
      <div className="form-grid">
        <div className="detail-group"><strong>Farm Name:</strong> <p>{farm.tenCoSo}</p></div>
        <div className="detail-group"><strong>Address:</strong> <p>{farm.diaChiCoSo}</p></div>
        <div className="form-group detail-group">
          <label>Species Name (đã có):</label>
          <select name="speciesName" value={activityFormData.speciesName} onChange={handleActivityFormChange}>
            <option value="">-- Select species --</option>
            {farm.loaiDongVatRung?.map((species, index) => (
              <option key={index} value={species.tenLamSan}>{species.tenLamSan}</option>
            ))}
          </select>
        </div>
      </div>

      <h3>Add New Tracking Record:</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        
        {/* NEW: Thêm chức năng Đăng ký lâm sản mới */}
        <div className="form-group-full-width" style={{ border: '1px dashed #007bff', padding: '15px', borderRadius: '8px', marginBottom: '15px' }}>
          <label style={{ fontWeight: 'bold', display: 'block', marginBottom: '10px', color: '#007bff' }}>
            Hoặc đăng ký lâm sản mới
          </label>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="newSpeciesSelection">Tên lâm sản mới:</label>
              <select id="newSpeciesSelection" value={selectedNewSpecies} onChange={handleNewSpeciesChange}>
                <option value="">-- Chọn hoặc nhập thủ công --</option>
                {speciesData.map((species, index) => (
                  <option key={index} value={species.tenLamSan}>{species.tenLamSan}</option>
                ))}
              </select>
            </div>
            {!isManualEntry && selectedNewSpecies && !selectedNewSpecies.includes("thủ công") && (
              <div className="form-group">
                <label>Tên khoa học (tự động):</label>
                <input type="text" value={activityFormData.newScientificName} readOnly disabled />
              </div>
            )}
            {isManualEntry && (
              <>
                <div className="form-group">
                  <label htmlFor="newSpeciesName">Tên lâm sản (nhập thủ công):</label>
                  <input type="text" name="newSpeciesName" value={activityFormData.newSpeciesName} onChange={handleActivityFormChange} required />
                </div>
                <div className="form-group">
                  <label htmlFor="newScientificName">Tên khoa học (nhập thủ công):</label>
                  <input type="text" name="newScientificName" value={activityFormData.newScientificName} onChange={handleActivityFormChange} />
                </div>
              </>
            )}
          </div>
        </div>
        
        <div className="form-grid">
          <div className="form-group">
            <label>Date Recorded:</label>
            <input type="date" name="date" value={activityFormData.date} onChange={handleActivityFormChange} required />
          </div>
          <div className="form-group">
            <label>Reason for Change:</label>
            <input type="text" name="reasonForChange" value={activityFormData.reasonForChange} onChange={handleActivityFormChange} />
          </div>
        </div>

        <div className="form-grid">
          {/* ... Phần Increase / Decrease giữ nguyên ... */}
        </div>
        
        <button type="submit" className="submit-button">Add Record</button>
      </form>

      <h3>Tracking History:</h3>
      {/* ... Bảng hiển thị và các nút khác giữ nguyên ... */}
    </div>
  );
}

export default FarmDetail;
